SELECT tank_name, AVG(average_wr) AS average_win_rate
FROM tanks
GROUP BY tank_name;

SELECT *
FROM tanks
WHERE CAST(battles AS INTEGER) > 5000;

SELECT t.tank_name, t.tank_id, tu.upgrade_name, tu.upgrade_cost
FROM tanks t
INNER JOIN tank_upgrades tu ON t.tank_id = tu.tank_id;

SELECT AVG(average_wr) AS average_success_rate
FROM tanks
WHERE tank_type = 'Researchable';

SELECT COUNT(*)
FROM players
INNER JOIN access_logs ON players.player_id = access_logs.player_id;

SELECT tank_name, armor
FROM tanks
WHERE armor = (SELECT MAX(armor) FROM tanks);

SELECT player_name, total_battles, total_wins
FROM players
ORDER BY total_wins DESC;
